<script>
  var adPlacements = {};
  var googletag = googletag || {};
  googletag.cmd = googletag.cmd || [];

  googletag.cmd.push(function() {
    googletag.pubads().enableSingleRequest()

      googletag.pubads().setPrivacySettings({ nonPersonalizedAds: true })

    googletag.pubads().disableInitialLoad()

    var yieldbirdOptimization = {
    targetingValue(name) {
      switch (name) {
        case 'bm':
          return Math.random() >= 0.1 ? '1' : '0';
        case 'ab':
          return this.dool ? 'b' : `a${Math.floor(Math.random() * 10)}`;
        case 'dc':
          return this.dool ? 'd' : `c${Math.floor(Math.random() * 20)}`;
        case 'mx':
          return this.dool ? `m${Math.floor(Math.random() * 180)}` : 'x';
        case 'tt':
          return `tt${Math.floor(Math.random() * 10)}`;
        default:
          return '';
      }
    },
    dool: Math.random() >= 0.1
};

var date = new Date(),
    minute = date.getUTCMinutes(),
    hour = date.getUTCHours() - 8,
    day = date.getUTCDay();

if (hour < 0) {
  hour = hour + 24;
  day -= 1;
}

if (day < 0) {
  day = day + 7;
}

googletag.pubads().setTargeting('yb_bm', yieldbirdOptimization.targetingValue('bm'));
googletag.pubads().setTargeting('yb_ab', yieldbirdOptimization.targetingValue('ab'));
googletag.pubads().setTargeting('yb_dc', yieldbirdOptimization.targetingValue('dc'));
googletag.pubads().setTargeting('yb_mx', yieldbirdOptimization.targetingValue('mx'));
googletag.pubads().setTargeting('yb_tt', yieldbirdOptimization.targetingValue('tt'));
googletag.pubads().setTargeting('yb_ff', '' + Math.round(Math.random()));
googletag.pubads().setTargeting('yb_th', hour.toString());
googletag.pubads().setTargeting('yb_tm', minute.toString());
googletag.pubads().setTargeting('yb_wd', day.toString());




    googletag.pubads().collapseEmptyDivs();
    googletag.enableServices();
  });
</script>


